# frozen_string_literal: true

class UserSuspender
  attr_reader :user_history

  def initialize(
    user,
    suspended_till:,
    reason:,
    by_user:,
    message: nil,
    post_id: nil,
    reviewable_id: nil
  )
    @user = user
    @suspended_till = suspended_till
    @reason = reason
    @by_user = by_user
    @message = message
    @post_id = post_id
    @reviewable_id = reviewable_id
  end

  def suspend
    suspended_at = DateTime.now

    @user.suspended_till = @suspended_till
    @user.suspended_at = suspended_at

    @user.transaction do
      @user.save!

      @user_history =
        StaffActionLogger.new(@by_user).log_user_suspend(
          @user,
          @reason,
          message: @message,
          post_id: @post_id,
          reviewable_id: @reviewable_id,
        )
    end
    @user.log_out!

    if @message.present?
      Jobs.enqueue(
        Jobs::CriticalUserEmail,
        type: "account_suspended",
        user_id: @user.id,
        user_history_id: @user_history.id,
      )
    end

    DiscourseEvent.trigger(
      :user_suspended,
      user: @user,
      reason: @reason,
      message: @message,
      user_history: @user_history,
      post_id: @post_id,
      suspended_till: @suspended_till,
      suspended_at: suspended_at,
    )
    nil
  end
end

# frozen_string_literal: true

class TopicTimestampChanger
  class InvalidTimestampError < StandardError
  end

  def initialize(timestamp:, topic: nil, topic_id: nil)
    @topic = topic || Topic.with_deleted.find(topic_id)
    @posts = @topic.posts
    @current_timestamp = Time.zone.now
    @timestamp = Time.zone.at(timestamp)

    raise InvalidTimestampError if @timestamp.to_f > @current_timestamp.to_f

    @time_difference = calculate_time_difference
  end

  def change!
    ActiveRecord::Base.transaction do
      last_posted_at = @timestamp

      @posts.each do |post|
        if post.is_first_post?
          update_post(post, @timestamp)
        else
          new_created_at = Time.at(post.created_at.to_f + @time_difference)
          new_created_at = @current_timestamp if new_created_at > @current_timestamp
          last_posted_at = new_created_at if new_created_at > last_posted_at
          update_post(post, new_created_at)
        end
      end

      @topic.reset_bumped_at
      update_topic(last_posted_at)

      yield(@topic) if block_given?
    end

    # Burst the cache for stats
    [AdminDashboardData, About].each { |klass| Discourse.redis.del klass.stats_cache_key }
  end

  private

  def calculate_time_difference
    @timestamp - @topic.created_at
  end

  def update_topic(last_posted_at)
    @topic.update(created_at: @timestamp, updated_at: @timestamp, last_posted_at: last_posted_at)
  end

  def update_post(post, timestamp)
    post.update(created_at: timestamp, updated_at: timestamp)
  end
end

# typed: strict
# frozen_string_literal: true

module Utils
  # Gets the full commit hash of the HEAD commit.
  sig {
    params(
      repo:   T.any(String, Pathname),
      length: T.nilable(Integer),
      safe:   T::Boolean,
    ).returns(T.nilable(String))
  }
  def self.git_head(repo = Pathname.pwd, length: nil, safe: true)
    return git_short_head(repo, length:) if length

    GitRepository.new(Pathname(repo)).head_ref(safe:)
  end

  # Gets a short commit hash of the HEAD commit.
  sig {
    params(
      repo:   T.any(String, Pathname),
      length: T.nilable(Integer),
      safe:   T::Boolean,
    ).returns(T.nilable(String))
  }
  def self.git_short_head(repo = Pathname.pwd, length: nil, safe: true)
    GitRepository.new(Pathname(repo)).short_head_ref(length:, safe:)
  end

  # Gets the name of the currently checked-out branch, or HEAD if the repository is in a detached HEAD state.
  sig {
    params(
      repo: T.any(String, Pathname),
      safe: T::Boolean,
    ).returns(T.nilable(String))
  }
  def self.git_branch(repo = Pathname.pwd, safe: true)
    GitRepository.new(Pathname(repo)).branch_name(safe:)
  end

  # Gets the full commit message of the specified commit, or of the HEAD commit if unspecified.
  sig {
    params(
      repo:   T.any(String, Pathname),
      commit: String,
      safe:   T::Boolean,
    ).returns(T.nilable(String))
  }
  def self.git_commit_message(repo = Pathname.pwd, commit: "HEAD", safe: true)
    GitRepository.new(Pathname(repo)).commit_message(commit, safe:)
  end
end
